changeSet.sql:
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = '${app_role_name}') THEN
        EXECUTE format('CREATE ROLE %I LOGIN PASSWORD %L', '${app_role_name}', '${app_role_password}');
    END IF;
END
$$;

GRANT USAGE ON SCHEMA public TO ${app_role_name};
-- Default deny, then grant the minimum each table class needs. REVOKE ALL ON ALL TABLES IN SCHEMA public FROM ${app_role_name};
-- Regulated MUTABLE tables: SELECT, INSERT, UPDATE (NO DELETE -> soft delete only). GRANT SELECT, INSERT, UPDATE ON sites, departments, roles, permissions, users, user_roles, role_permissions, attachments, record_comments, record_sequences, organizations, organization_sites, plans, modules, plan_modules, organization_subscriptions, organization_licenses, organization_module_licenses, platform_admins, organization_settings, numbering_schemes, organization_notification_templates, settings_change_requests, qms_processes, record_retention_policies, record_legal_holds, documents, document_folders, document_notes, document_approval_profiles, document_read_assignments, change_controls, change_control_departments, change_control_impact_tasks, capas, capa_actions, deviations, products, product_specifications, product_material_components, product_process_info, product_qc_requirements, product_documents, product_quality_issue_links, product_risk_links, product_change_control_links, product_approval_history, materials, batch_records, batch_production_steps, batch_materials_used, batch_qc_results, batch_deviations_link, batch_products_produced, notifications, complaints, complaint_investigation, complaint_resolution, complaint_capa_link, complaint_timeline, audits, audit_findings, audit_capa_link, audit_follow_up, risks, risk_analysis, risk_mitigation, risk_control_effectiveness, suppliers, supplier_qualifications, supplier_certifications, supplier_performance, supplier_findings, supplier_capa_link, training_programs, training_assignments, training_auto_rules, training_completion_audit, equipment, calibrations, maintenance_history, equipment_specifications, oos_cases, oos_initial_assessment, oos_repeat_testing, oos_investigation, oos_disposition, oos_capa_link, oos_containment, oos_investigation_items, oos_retest_resample, oos_impact_assessment, oos_root_cause, oos_linked_records, oos_evidence, non_conformances, non_conformance_investigation, non_conformance_disposition, non_conformance_use_as_is_approval, non_conformance_capa_link, management_reviews, review_metrics, review_audit_results, review_product_feedback, review_action_items, review_decisions TO ${app_role_name};
-- Append-only document version history: SELECT + INSERT only (immutable snapshots). GRANT SELECT, INSERT ON document_versions TO ${app_role_name};
-- Reference links are fixed at intake and append-only for the runtime role. GRANT SELECT, INSERT ON document_references TO ${app_role_name};
-- Append-only audit trail: SELECT + INSERT only. GRANT SELECT, INSERT ON audit_logs TO ${app_role_name};
-- Append-only organization admin settings audit trail. GRANT SELECT, INSERT ON admin_settings_audit_logs TO ${app_role_name};
-- Immutable signatures: SELECT + INSERT only. GRANT SELECT, INSERT ON electronic_signatures TO ${app_role_name};
-- Identity-column / sequence usage. GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO ${app_role_name};
